class CardDetails {
  final String cardNumber;
  final String expiryMonth;
  final String expiryYear;
  final String cvv;
  final String? cardHolderName;

  CardDetails({
    required this.cardNumber,
    required this.expiryMonth,
    required this.expiryYear,
    required this.cvv,
    this.cardHolderName,
  });

  bool isValid() {
    if (!_isValidCardNumber(cardNumber)) return false;
    if (!_isValidExpiry(expiryMonth, expiryYear)) return false;
    if (!_isValidCVV(cvv)) return false;
    return true;
  }

  bool _isValidCardNumber(String number) {
    final cleaned = number.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;
    return _luhnCheck(cleaned);
  }

  bool _luhnCheck(String cardNumber) {
    int sum = 0;
    bool alternate = false;
    for (int i = cardNumber.length - 1; i >= 0; i--) {
      int n = int.parse(cardNumber[i]);
      if (alternate) {
        n *= 2;
        if (n > 9) n -= 9;
      }
      sum += n;
      alternate = !alternate;
    }
    return (sum % 10 == 0);
  }

  bool _isValidExpiry(String month, String year) {
    final m = int.tryParse(month);
    final y = int.tryParse(year);
    if (m == null || y == null) return false;
    if (m < 1 || m > 12) return false;
    final now = DateTime.now();
    final expiry = DateTime(2000 + y, m);
    return expiry.isAfter(now);
  }

  bool _isValidCVV(String cvv) {
    return cvv.length >= 3 && cvv.length <= 4 && int.tryParse(cvv) != null;
  }

  String getCardType() {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (RegExp(r'^4').hasMatch(cleaned)) return 'Visa';
    if (RegExp(r'^5[1-5]').hasMatch(cleaned)) return 'Mastercard';
    if (RegExp(r'^3[47]').hasMatch(cleaned)) return 'Amex';
    if (RegExp(r'^6(?:011|5)').hasMatch(cleaned)) return 'Discover';
    return 'Unknown';
  }
}

class PaymentEncryption {
  static String encryptCardData(CardDetails card, String publicKey) {
    final data = jsonEncode({
      'number': card.cardNumber,
      'exp_month': card.expiryMonth,
      'exp_year': card.expiryYear,
      'cvc': card.cvv,
    });
    final bytes = utf8.encode(data + publicKey);
    final digest = sha256.convert(bytes);
    return base64.encode(digest.bytes);
  }

  static String generateIdempotencyKey() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final random = DateTime.now().microsecondsSinceEpoch;
    final data = '$timestamp-$random';
    final bytes = utf8.encode(data);
    final digest = sha256.convert(bytes);
    return digest.toString();
  }
}

class StripePaymentGateway {
  final PaymentConfig config;
  final http.Client _client;

  StripePaymentGateway(this.config) : _client = http.Client();

  Future<PaymentResult> processPayment(
      PaymentRequest request, CardDetails? cardDetails) async {
    try {
      final token = await _createCardToken(cardDetails!);
      if (token == null) {
        return PaymentResult(
          success: false,
          status: PaymentStatus.failed,
          message: 'Failed to create card token',
        );
      }

      final charge = await _createCharge(request, token);
      return charge;
    } catch (e) {
      return PaymentResult(
        success: false,
        status: PaymentStatus.failed,
        message: e.toString(),
      );
    }
  }

  Future<String?> _createCardToken(CardDetails card) async {
    final url = Uri.parse('https://api.stripe.com/v1/tokens');
    final response = await _client.post(
      url,
      headers: {
        'Authorization': 'Bearer ${config.stripePublishableKey}',
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: {
        'card[number]': card.cardNumber.replaceAll(' ', ''),
        'card[exp_month]': card.expiryMonth,
        'card[exp_year]': card.expiryYear,
        'card[cvc]': card.cvv,
      },
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      return data['id'];
    }
    return null;
  }

  Future<PaymentResult> _createCharge(
      PaymentRequest request, String token) async {
    final url = Uri.parse('https://api.stripe.com/v1/charges');
    final response = await _client.post(
      url,
      headers: {
        'Authorization': 'Bearer ${config.stripeSecretKey}',
        'Content-Type': 'application/x-www-form-urlencoded',
        'Idempotency-Key': PaymentEncryption.generateIdempotencyKey(),
      },
      body: {
        'amount': (request.amount * 100).toInt().toString(),
        'currency': request.currency.toLowerCase(),
        'source': token,
        'description': request.description,
      },
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      return PaymentResult(
        success: true,
        transactionId: data['id'],
        status: PaymentStatus.completed,
        message: 'Payment successful',
        metadata: data,
      );
    } else {
      final error = jsonDecode(response.body);
      return PaymentResult(
        success: false,
        status: PaymentStatus.failed,
        message: error['error']['message'],
      );
    }
  }

  Future<PaymentResult> refundPayment(String chargeId, double? amount) async {
    final url = Uri.parse('https://api.stripe.com/v1/refunds');
    final body = {'charge': chargeId};
    if (amount != null) {
      body['amount'] = (amount * 100).toInt().toString();
    }

    final response = await _client.post(
      url,
      headers: {
        'Authorization': 'Bearer ${config.stripeSecretKey}',
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body,
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      return PaymentResult(
        success: true,
        transactionId: data['id'],
        status: PaymentStatus.refunded,
        message: 'Refund successful',
      );
    } else {
      return PaymentResult(
        success: false,
        status: PaymentStatus.failed,
        message: 'Refund failed',
      );
    }
  }
}

class PayPalPaymentGateway {
  final PaymentConfig config;
  final http.Client _client;
  String? _accessToken;
  DateTime? _tokenExpiry;

  PayPalPaymentGateway(this.config) : _client = http.Client();

  String get _baseUrl => config.environment == 'production'
      ? 'https://api.paypal.com'
      : 'https://api.sandbox.paypal.com';

  Future<String?> _getAccessToken() async {
    if (_accessToken != null &&
        _tokenExpiry != null &&
        DateTime.now().isBefore(_tokenExpiry!)) {
      return _accessToken;
    }

    final url = Uri.parse('$_baseUrl/v1/oauth2/token');
    final credentials =
        base64.encode(utf8.encode('${config.paypalClientId}:${config.paypalSecret}'));

    final response = await _client.post(
      url,
      headers: {
        'Authorization': 'Basic $credentials',
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: {'grant_type': 'client_credentials'},
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      _accessToken = data['access_token'];
      _tokenExpiry = DateTime.now().add(Duration(seconds: data['expires_in']));
      return _accessToken;
    }
    return null;
  }

  Future<PaymentResult> processPayment(PaymentRequest request) async {
    try {
      final token = await _getAccessToken();
      if (token == null) {
        return PaymentResult(
          success: false,
          status: PaymentStatus.failed,
          message: 'Authentication failed',
        );
      }

      final url = Uri.parse('$_baseUrl/v2/checkout/orders');
      final response = await _client.post(
        url,
        headers: {
          'Authorization': 'Bearer $token',
          'Content-Type': 'application/json',
        },
        body: jsonEncode({
          'intent': 'CAPTURE',
          'purchase_units': [
            {
              'amount': {
                'currency_code': request.currency.toUpperCase(),
                'value': request.amount.toStringAsFixed(2),
              },
              'description': request.description,
            }
          ],
        }),
      );

      if (response.statusCode == 201) {
        final data = jsonDecode(response.body);
        return PaymentResult(
          success: true,
          transactionId: data['id'],
          status: PaymentStatus.completed,
          message: 'Payment order created',
          metadata: data,
        );
      } else {
        return PaymentResult(
          success: false,
          status: PaymentStatus.failed,
          message: 'Payment failed',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        status: PaymentStatus.failed,
        message: e.toString(),
      );
    }
  }

  Future<PaymentResult> capturePayment(String orderId) async {
    final token = await _getAccessToken();
    if (token == null) {
      return PaymentResult(
        success: false,
        status: PaymentStatus.failed,
        message: 'Authentication failed',
      );
    }

    final url = Uri.parse('$_baseUrl/v2/checkout/orders/$orderId/capture');
    final response = await _client.post(
      url,
      headers: {
        'Authorization': 'Bearer $token',
        'Content-Type': 'application/json',
      },
    );

    if (response.statusCode == 201) {
      final data = jsonDecode(response.body);
      return PaymentResult(
        success: true,
        transactionId: data['id'],
        status: PaymentStatus.completed,
        message: 'Payment captured',
        metadata: data,
      );
    } else {
      return PaymentResult(
        success: false,
        status: PaymentStatus.failed,
        message: 'Capture failed',
      );
    }
  }
}

class InAppPurchaseManager {
